function newKeyRingAndUSDCWithdrawal(
  address userSigningKey,
  address targetKeyRing,
  address smartWallet,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas,
  bytes calldata userSignature,
  bytes calldata dharmaSignature
) external returns (address keyRing, bool withdrawalSuccess) {
  // Deploy and initialize a keyring if needed and emit a corresponding event.
  keyRing = _deployNewKeyRingIfNeeded(userSigningKey, targetKeyRing);

  // Attempt to withdraw USDC from the provided smart wallet.
  withdrawalSuccess = DharmaSmartWalletImplementationV0Interface(
    smartWallet
  ).withdrawUSDC(
    amount, recipient, minimumActionGas, userSignature, dharmaSignature
  );
}

function _getKeyRingVersion() private view returns (uint256 version) {
  // Perform the staticcall into the key ring upgrade beacon.
  (bool ok, bytes memory data) = _KEY_RING_UPGRADE_BEACON.staticcall("");

  // Revert if underlying staticcall reverts, passing along revert message.
  require(ok, string(data));

  // Ensure that the data returned from the beacon is the correct length.
  require(data.length == 32, "Return data must be exactly 32 bytes.");

  // Decode the implementation address from the returned data.
  address implementation = abi.decode(data, (address));

  // Call into the implementation address directly to get the version.
  version = DharmaKeyRingImplementationV0Interface(
    implementation
  ).getVersion();
}

function newSmartWallet(
  address userSigningKey
) external returns (address wallet) {
  // Get initialization calldata from initialize selector & user signing key.
  bytes memory initializationCalldata = abi.encodeWithSelector(
    _initializer.initialize.selector,
    userSigningKey
  );

  // Initialize and deploy new user smart wallet as an Upgrade Beacon proxy.
  wallet = _deployUpgradeBeaconProxyInstance(initializationCalldata);

  // Emit an event to signal the creation of the new smart wallet.
  emit SmartWalletDeployed(wallet, userSigningKey);
}

function matchesRegisteredCodeHash(
  address target
) external view returns (bool codeHashMatchesRegisteredCodeHash) {
  // Get the runtime code hash that is currently registered for the target.
  bytes32 cachedCodeHash = _cachedHashes[target];

  // Ensure that the target contract has already had a code hash registered.
  require(cachedCodeHash != bytes32(0), "Target not yet registered.");

  // Retrieve the current runtime code hash of the target contract.
  bytes32 currentCodeHash;
  assembly { currentCodeHash := extcodehash(target) }

  // Compare current runtime code hash to registered runtime code hash.
  codeHashMatchesRegisteredCodeHash = currentCodeHash == cachedCodeHash;
}

function canCallWithDelay(
    address authority,
    address caller,
    address target,
    bytes4 selector
) internal view returns (bool immediate, uint32 delay) {
    bytes memory data = abi.encodeCall(IAuthority.canCall, (caller, target, selector));

    assembly ("memory-safe") {
        mstore(0x00, 0x00)
        mstore(0x20, 0x00)

        if staticcall(gas(), authority, add(data, 0x20), mload(data), 0x00, 0x40) {
            immediate := mload(0x00)
            delay := mload(0x20)

            // If delay does not fit in a uint32, return 0 (no delay)
            // equivalent to: if gt(delay, 0xFFFFFFFF) { delay := 0 }
            delay := mul(delay, iszero(shr(32, delay)))
        }
    }
}

function proposeUpgrade(
    address proxyAddress,
    string memory newImplementationContractName,
    Options memory opts
) internal returns (ProposeUpgradeResponse memory) {
    opts.defender.useDefenderDeploy = true;
    address proxyAdminAddress = Core.getAdminAddress(proxyAddress);
    address newImplementationAddress = Core.prepareUpgrade(newImplementationContractName, opts);
    return
        DefenderDeploy.proposeUpgrade(
            proxyAddress,
            proxyAdminAddress,
            newImplementationAddress,
            newImplementationContractName,
            opts
        );
}
